SELECT lowest_frequency_permitted
FROM frequency_regulations
WHERE region_name = 'EU' AND regulation_type = 1;

SELECT MAX(highest_frequency_permitted) AS max_highest_frequency_permitted
FROM frequency_regulations
WHERE country_name = 'Russia' AND region_name = 'EU';

SELECT lowest_frequency_permitted
FROM frequency_regulations
WHERE serial_code = '0x15';

SELECT *
FROM frequency_regulations
WHERE country_name = 'Russia' AND lowest_frequency_permitted BETWEEN 25000 AND 35000;

SELECT region_name, AVG(highest_frequency_permitted) AS average_highest_frequency
FROM frequency_regulations
GROUP BY region_name;

SELECT MAX(highest_frequency_permitted) AS highest_frequency
FROM frequency_regulations
WHERE regulation_type = (SELECT id FROM regulation_types WHERE name = 'International');

SELECT HEX(COUNT(*)) AS hexadecimal_count
FROM frequency_regulations
WHERE region_name = 'Asia' AND channel_hop_table_high > channel_hop_table_low;

SELECT description 
FROM frequency_bands 
WHERE lowest_frequency = (SELECT MAX(lowest_frequency) FROM frequency_bands);

SELECT lowest_frequency_permitted
FROM frequency_regulations
WHERE country_name = 'Singapore' AND region_name = 'Europe';
